INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('55145ca3-38c5-472e-91e5-8e0f54c3f703', $q$Platinum$q$, $q$$93/month ($77/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["25 projects/folders","100 content writer analyses/month","60,000 AI credits"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('55145ca3-38c5-472e-91e5-8e0f54c3f703', $q$Diamond$q$, $q$$117/month ($97/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["50 projects/folders","150 content writer analyses/month","Designed for agencies"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('55145ca3-38c5-472e-91e5-8e0f54c3f703', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$NeuronWriter is a semantic SEO content optimization platform that scores content against top-ranking search results using NLP and real-time SERP analysis. It was founded in 2019 in Poland by Pawel Sokolowski and Damian Kielbasa, the team behind the related Contadu content intelligence platform.$q$, $q$The company is a small, bootstrapped operation with roughly 6 employees and no outside venture funding, having previously built other SEO tools for the Polish market before launching NeuronWriter as a standalone product for individuals and small teams.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('55145ca3-38c5-472e-91e5-8e0f54c3f703', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$NeuronWriter's core content score measures a draft against the terms, headings, and topics used by pages currently ranking for a target keyword, paired with shareable content briefs and an AI writing assistant built directly into the editor. Internal linking suggestions, plagiarism checks, and readability scoring round out the content workflow.$q$, $q$Newer AI-visibility tracking capabilities monitor how content performs in AI-generated search answers, reflecting the platform's expansion beyond traditional Google SERP optimization as search behavior evolves.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('55145ca3-38c5-472e-91e5-8e0f54c3f703', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$NeuronWriter offers five tiers priced per month, each discounted for annual billing: Bronze at 23 dollars (19 dollars annual), Silver at 45 dollars (37 dollars annual), Gold at 69 dollars (57 dollars annual), Platinum at 93 dollars (77 dollars annual), and Diamond at 117 dollars (97 dollars annual), which is aimed at agencies.$q$, $q$Plans differ mainly by the number of projects and folders, the number of monthly content writer analyses, and the amount of included AI credits. NeuronWriter has also been sold via lifetime-deal platforms such as AppSumo.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f36057a5-8bfe-46d6-b430-56cb10cd464c', $q$Application Performance Monitoring (APM)$q$, $q$Deep tracing and performance monitoring for applications across languages and frameworks.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f36057a5-8bfe-46d6-b430-56cb10cd464c', $q$Infrastructure Monitoring$q$, $q$Real-time visibility into servers, containers, and cloud infrastructure.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f36057a5-8bfe-46d6-b430-56cb10cd464c', $q$Log Management$q$, $q$Centralized log ingestion, search, and correlation with metrics and traces.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f36057a5-8bfe-46d6-b430-56cb10cd464c', $q$Full-Stack Observability$q$, $q$Unifies metrics, events, logs, and traces in a single data platform called NRDB.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f36057a5-8bfe-46d6-b430-56cb10cd464c', $q$Synthetic Monitoring$q$, $q$Scripted and simple browser checks to proactively test uptime and performance.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f36057a5-8bfe-46d6-b430-56cb10cd464c', $q$AI Monitoring$q$, $q$Observability for LLM and AI application performance, cost, and quality.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f36057a5-8bfe-46d6-b430-56cb10cd464c', $q$Custom Dashboards and Alerts$q$, $q$Build unified dashboards and configurable alert policies across all monitored data.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f36057a5-8bfe-46d6-b430-56cb10cd464c', $q$Errors Inbox and Applied Intelligence$q$, $q$AI-assisted incident correlation and anomaly detection to speed up root-cause analysis.$q$, 7);
