INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f36057a5-8bfe-46d6-b430-56cb10cd464c', $q$Full platform user pricing is significantly more expensive than core or basic users on the Pro tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f36057a5-8bfe-46d6-b430-56cb10cd464c', $q$Feature sprawl across 50-plus capabilities can create a learning curve for new teams$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f36057a5-8bfe-46d6-b430-56cb10cd464c', $q$Competition from more focused or cheaper observability tools on specific use cases$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f36057a5-8bfe-46d6-b430-56cb10cd464c', $q$What is New Relic?$q$, $q$New Relic is an observability platform that unifies application performance monitoring, infrastructure monitoring, logs, and more into a single data platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f36057a5-8bfe-46d6-b430-56cb10cd464c', $q$Who founded New Relic?$q$, $q$New Relic was founded in 2008 by Lew Cirne, who previously founded the APM company Wily Technology.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f36057a5-8bfe-46d6-b430-56cb10cd464c', $q$Is New Relic still a public company?$q$, $q$No, New Relic went public via IPO in December 2014 but was acquired by private equity firms Francisco Partners and TPG for approximately 6.5 billion dollars, completing in November 2023, and is now privately held.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f36057a5-8bfe-46d6-b430-56cb10cd464c', $q$Does New Relic have a free tier?$q$, $q$Yes, New Relic offers a perpetual free tier with 100 GB of monthly data ingest, one full platform user, and unlimited basic and core users.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f36057a5-8bfe-46d6-b430-56cb10cd464c', $q$How is New Relic priced?$q$, $q$Pricing combines a per-user fee for full platform users on the Standard or Pro tiers plus consumption-based data ingest charges beyond the free 100 GB, with custom Enterprise pricing for large organizations.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f36057a5-8bfe-46d6-b430-56cb10cd464c', $q$Where is New Relic headquartered?$q$, $q$New Relic is headquartered in San Francisco, California.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f36057a5-8bfe-46d6-b430-56cb10cd464c', $q$What does New Relic compete with?$q$, $q$New Relic competes with observability and monitoring platforms such as Datadog, Dynatrace, Splunk, Grafana, and Netdata.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f36057a5-8bfe-46d6-b430-56cb10cd464c', $q$Application performance monitoring for engineering teams$q$, $q$Software teams use New Relic APM to trace and optimize application performance across microservices.$q$, $q$Software engineering and DevOps teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f36057a5-8bfe-46d6-b430-56cb10cd464c', $q$Enterprise-wide observability consolidation$q$, $q$Large enterprises consolidate APM, infrastructure, and log monitoring into one unified New Relic platform to reduce tool sprawl.$q$, $q$Enterprise IT and platform engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f36057a5-8bfe-46d6-b430-56cb10cd464c', $q$Startup and small-team monitoring on the free tier$q$, $q$Small teams and startups use New Relic's free 100 GB tier to get production monitoring without upfront cost.$q$, $q$Startups and small engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f36057a5-8bfe-46d6-b430-56cb10cd464c', $q$Free$q$, $q$$0/month$q$, $q$Monthly$q$, NULL, $q$["100 GB data ingest/month","1 full platform user","Unlimited basic and core users","Access to 50+ capabilities"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f36057a5-8bfe-46d6-b430-56cb10cd464c', $q$Standard$q$, $q$From $10 (first full user)$q$, $q$Monthly$q$, NULL, $q$["100 GB data ingest/month","Up to 5 full platform users at $99 each","Core users at $49 each","Ticketed support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f36057a5-8bfe-46d6-b430-56cb10cd464c', $q$Pro$q$, $q$$349/user/year (or ~$418.80/month)$q$, $q$Annual or monthly$q$, NULL, $q$["Unlimited full platform users","Core users at $49 each","Priority support with 2-hour critical SLA","Advanced features"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f36057a5-8bfe-46d6-b430-56cb10cd464c', $q$Enterprise$q$, $q$Custom$q$, $q$Annual contract$q$, NULL, $q$["Custom data ingest and user pricing","Dedicated support and SLAs","Advanced security and compliance"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f36057a5-8bfe-46d6-b430-56cb10cd464c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$New Relic is an observability platform that unifies application performance monitoring, infrastructure monitoring, log management, and more into a single underlying data platform. It was founded in 2008 by Lew Cirne, a veteran of the APM category who previously founded Wily Technology, and is headquartered in San Francisco.$q$, $q$New Relic went public via IPO in December 2014 and remained publicly traded until it was acquired by private equity firms Francisco Partners and TPG for about 6.5 billion dollars, a deal that closed in November 2023 and returned the company to private ownership.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f36057a5-8bfe-46d6-b430-56cb10cd464c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$New Relic's core architecture is a unified data platform, internally called NRDB, that ingests metrics, events, logs, and traces into one queryable store so teams can correlate infrastructure alerts, application traces, and log lines without switching tools. Capabilities span APM, infrastructure monitoring, log management, synthetic monitoring, and more than 50 features in total.$q$, $q$Newer capabilities include AI monitoring for observing the performance and cost of LLM-powered applications, alongside an Errors Inbox with AI-assisted anomaly correlation branded Applied Intelligence for faster root-cause analysis.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f36057a5-8bfe-46d6-b430-56cb10cd464c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$New Relic combines per-user pricing with consumption-based data ingest charges. The perpetual Free tier includes 100 GB of monthly ingest, one full platform user, and unlimited basic and core users across all capabilities.$q$, $q$The Standard tier starts at 10 dollars for the first full user plus 99 dollars per additional full user, the Pro tier offers unlimited full users at 349 dollars per user annually with priority support, and Enterprise pricing is fully custom. Ingest beyond the free allotment costs 0.40 dollars per gigabyte for standard data or 0.60 dollars for the higher-retention Data Plus option.$q$]::text[], 2);
