-- ── NetBox ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$NetBox is an open-source network source-of-truth platform that combines IP address management (IPAM) and data center infrastructure management (DCIM) to power network automation.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE($q$11-50 employees (NetBox Labs)$q$, company_size),
  headquarters = COALESCE($q$New York, New York, United States (NetBox Labs)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$NetBox Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$NetBox review 2026: the free, open-source IPAM and DCIM source of truth for network automation. Compare NetBox Community, Cloud and Enterprise pricing and features.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$NetBox is an open-source network source-of-truth platform that unifies IP address management (IPAM) and data center infrastructure management (DCIM) into a single, extensible data model. It was originally created in 2016 by Jeremy Stretch while he worked at DigitalOcean, who built it to replace a patchwork of spreadsheets and legacy tools used to document DigitalOcean's own network. NetBox is built on Python and the Django web framework with a PostgreSQL database, and it was released as free, open-source software under the Apache 2.0 license via the netbox-community GitHub organization, where it has grown into one of the most widely adopted network documentation tools, used by thousands of organizations to model devices, racks, cabling, circuits, IP prefixes, VLANs, and VRFs. In 2023, a dedicated commercial company called NetBox Labs was spun out of NS1 (the DNS and traffic management company that had been acquired by IBM), co-founded by former NS1 CEO Kris Beevers and NetBox creator Jeremy Stretch, to steward the open-source project and sell commercial offerings around it. NetBox Labs raised 20 million dollars in Series A funding in April 2023, led by Flybridge Capital with participation from GGV Capital, Grafana Labs CEO Raj Dutt, Mango Capital, Salesforce Ventures, Two Sigma Ventures, IBM, Founder Collective, and Entree Capital, and it operates out of New York with roughly 11 to 50 employees. NetBox's product line spans three tiers: NetBox Community, the free, self-hosted, open-source core; NetBox Cloud, a fully managed SaaS version handling upgrades, backups, and enterprise security controls; and NetBox Enterprise, a self-hosted commercial edition with vendor support and SLAs. Core features include a highly extensible data model that supports custom fields, tags, and custom object types, a large community plugin ecosystem covering things like wireless and circuits, REST and GraphQL APIs for infrastructure-as-code and automation workflows built with tools like Ansible and Terraform, and built-in change logging and journaling for auditing infrastructure state over time. NetBox's target audience is network engineers, NetOps and platform teams, data center operators, and managed service providers who need a canonical, API-driven inventory of their physical and logical network state to drive automation pipelines. Pricing for the open-source Community edition is free; NetBox Cloud and NetBox Enterprise are both sold on custom, quote-based pricing requiring a sales conversation with NetBox Labs. Competitors and adjacent tools in the network source-of-truth and IPAM/DCIM space include Device42, Infoblox, phpIPAM, Racktables, SolarWinds IPAM, and general-purpose CMDB platforms, though NetBox differentiates itself through its open-source-first model, deep API-driven extensibility, and status as the de facto standard data model referenced throughout the network automation community, particularly among users of tools like Nornir, NAPALM, and Ansible network modules.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'aec1c6d5-ecc8-46ac-9da2-4a389876a94b';

