-- ── NetHunt CRM ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$NetHunt CRM is a sales CRM that integrates natively into Gmail and Google Workspace, letting teams manage leads, pipelines, and communication without leaving their inbox.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$24/user/month (billed annually)$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$~15 employees$q$, company_size),
  headquarters = COALESCE($q$Kyiv, Ukraine$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$NetHunt CRM Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$NetHunt CRM review 2026: a Gmail-native sales CRM for pipelines, email tracking, and automation. Compare Basic, Business, and Business Plus pricing plans.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$NetHunt CRM is a sales customer relationship management platform that embeds directly inside Gmail and the broader Google Workspace ecosystem, so sales teams can manage contacts, deals, pipelines, and communication without switching away from their inbox. The company was founded in 2015 and started in Kyiv, Ukraine, where it remains headquartered, and it is a member of the IT Ukraine Association trade group. NetHunt is a relatively small, lean company with approximately 15 employees distributed across Europe and North America as of the mid-2020s, reflecting a bootstrapped or lightly funded growth path rather than a large venture-backed scale-up. The product's defining architectural choice is that it does not operate as a separate application users must switch to; instead, it installs as a sidebar and set of extensions inside Gmail, turning existing email threads, contacts, and folders into structured CRM records, deals, and pipeline stages. Core functionality includes customizable visual sales pipelines for tracking deals from lead to close, email open and click tracking, reusable email templates, bulk email campaign sending directly from Gmail, a LinkedIn browser extension that captures profile data into CRM records, workflow automation for repetitive tasks like lead assignment and follow-up reminders, shared team folders and records for collaboration, flexible custom fields, and reporting dashboards for sales performance and pipeline velocity. NetHunt offers a 14-day free trial with no restriction on the number of invited users. Its pricing is structured across four tiers billed per user per month: Basic at 30 dollars per user per month (about 24 dollars with a 20 percent annual billing discount), Basic Plus at 42 dollars, Business at 60 dollars, and Business Plus at 84 dollars, with each tier unlocking progressively more automation, integrations, and reporting depth. NetHunt also runs targeted discount programs: startups founded within the previous three years can apply for a 75 percent discount on the Business plan for their first 12 months, and registered non-profit organizations can receive a 25 percent discount, both arranged by contacting the sales team directly. NetHunt's target audience is small and mid-sized sales teams, agencies, recruiters, and partnership managers who are already deeply embedded in the Google Workspace ecosystem and want CRM functionality without adopting a separate standalone tool. Its main competitors include other lightweight or Gmail-adjacent CRMs such as Streak, Copper, and Salesflare, as well as broader CRM platforms like HubSpot, Pipedrive, and Salesforce, against which NetHunt differentiates itself primarily through its deep, native Gmail integration and lower price point relative to enterprise CRM suites.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'aade9c0c-6fb6-412a-9dc0-66e5e626d8a8';

