-- ── Netlify ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Netlify is a cloud platform for building, deploying, and hosting modern web applications, known for its git-based continuous deployment workflow for JAMstack and framework-driven sites.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$100-250 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Netlify Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Netlify review 2026: git-based deployment, edge functions, and global hosting for modern web apps. Compare Free, Personal, Pro and Enterprise pricing plans.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Netlify is a cloud platform for building, deploying, and hosting modern web applications, best known for popularizing git-based continuous deployment for static sites and JAMstack applications. It was founded on July 10, 2014, by Danish entrepreneur Mathias 'Matt' Biilmann, who had previously run a content management startup called Webpop, and his childhood friend Christian Bach, who joined as co-founder after working as an executive at a creative services agency in Denmark. The company is headquartered in San Francisco, California, and has raised approximately 212 million dollars in total funding across five rounds from investors including Andreessen Horowitz, Bessemer Venture Partners, and Bloomberg Beta, with its most recent disclosed round being a 105 million dollar Series D in November 2021 that valued the company at around 2 billion dollars, making it a unicorn. Employee count estimates from various data providers in 2026 range roughly from about 110 to over 200, suggesting a workforce in the range of 100 to 250 people. Netlify's product architecture centers on connecting a git repository on GitHub, GitLab, or Bitbucket to automatically trigger builds and deployments on every push, with every branch or pull request receiving its own live deploy preview URL for team review. Sites are served from a global edge network and CDN for fast load times worldwide, and the platform supports serverless functions and edge functions for running backend logic without managing infrastructure, along with Netlify Forms for collecting form submissions on static sites and Netlify Identity for built-in authentication. Netlify natively supports popular frameworks including Next.js, Astro, Gatsby, Hugo, and Remix with minimal configuration, and it has expanded over time from purely static site hosting into full support for server-side rendering and more complex modern web architectures, including newer AI-assisted build tooling. Pricing has shifted to a credit-based model as of 2025 to 2026: a Free plan offers 300 credits per month, a Personal plan costs 9 dollars per month for 1,000 credits, a Pro plan starts at 20 dollars per month with 3,000 scalable credits and, as of an April 2026 pricing change, unlimited team seats included in that flat fee, and an Enterprise plan offers custom pricing with advanced security, compliance, and SLAs. Netlify's target audience spans individual frontend developers and hobbyists on the free tier, marketing teams and agencies building fast, SEO-friendly sites, and larger enterprise engineering organizations that need multi-team deployment governance. Its main competitors include Vercel, Cloudflare Pages, AWS Amplify, and GitHub Pages, with Netlify differentiating itself through its early-mover JAMstack ecosystem, broad framework support, and integrated forms, identity, and functions offerings alongside its core hosting product.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '26474910-f9a4-4767-aebb-d9caf5983498';

