-- ── New Relic ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$New Relic is an observability platform that unifies application performance monitoring, infrastructure monitoring, logs, and more into a single data platform for engineering teams.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2008, founded_year),
  company_size = COALESCE($q$~3,000 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$New Relic Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$New Relic review 2026: full-stack observability with APM, infrastructure, and log monitoring. Compare the free 100GB tier to Standard, Pro, and Enterprise.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$New Relic is an observability platform that unifies application performance monitoring (APM), infrastructure monitoring, log management, browser and mobile monitoring, synthetic monitoring, and AI monitoring into a single underlying data platform. The company was founded in 2008 by Lew Cirne, a serial software entrepreneur who had previously founded the application performance monitoring company Wily Technology, and it is headquartered in San Francisco, California. New Relic went public on the New York Stock Exchange in December 2014, raising approximately 115 million dollars in its IPO and reaching an initial market capitalization above 1.4 billion dollars. The company remained publicly traded for nearly a decade until July 2023, when private equity firms Francisco Partners and TPG announced an agreement to acquire New Relic for approximately 6.5 billion dollars; the deal closed in November 2023, taking the company private and ending its era of public financial disclosure. As of the mid-2020s, New Relic employs roughly 3,000 people distributed across teams on multiple continents. Architecturally, New Relic's differentiator is its unified telemetry data platform, internally referred to as NRDB, which ingests metrics, events, logs, and traces (often summarized as MELT data) into one queryable store rather than siloed tools for each data type, letting customers correlate an infrastructure alert with an application trace and a log line inside one interface. The platform offers more than 50 capabilities, including APM with distributed tracing across languages and frameworks, real-time infrastructure and Kubernetes monitoring, centralized log management, synthetic monitoring for uptime and performance checks, an Errors Inbox with AI-assisted anomaly correlation branded Applied Intelligence, custom dashboards and alert policies, and a newer AI monitoring capability for observing the performance, cost, and quality of LLM-powered applications. New Relic's pricing model, restructured around 2020 away from legacy per-host pricing, combines a per-user fee with consumption-based data ingest charges: a perpetual Free tier includes 100 GB of monthly data ingest, one full platform user, and unlimited basic and core users across all 50-plus capabilities; the Standard tier charges 10 dollars for the first full platform user and 99 dollars for each additional full user up to five, plus 49 dollars per core user, with 100 GB of included ingest; the Pro tier offers unlimited full platform users at 349 dollars per user annually (equivalent to about 418.80 dollars per month billed separately) with 49-dollar core users and priority support carrying a two-hour critical SLA; and Enterprise pricing is fully custom for large, complex organizations. Data ingested beyond the free allotment is billed at 0.40 dollars per gigabyte for standard data or 0.60 dollars per gigabyte for the higher-retention Data Plus tier. New Relic's target audience ranges from individual developers and startups using the generous free tier, to mid-sized software engineering and DevOps teams standardizing on APM, up to large enterprises consolidating many monitoring tools into one platform. Its principal competitors in the observability and monitoring market include Datadog, Dynatrace, Splunk, Grafana Labs, and Netdata, with New Relic differentiating itself through the breadth of its unified platform, deep historical presence as a pioneer of the APM category, and its perpetual free tier.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f36057a5-8bfe-46d6-b430-56cb10cd464c';

